const childWorkflows = ['CWF-210', 'CWF-220', 'CWF-230', 'CWF-240'];
let executionPlan = { workflows_to_execute: childWorkflows, current_index: 0, status: 'PLANNING', decisions: { quality_gate: true, governance_gate: true } };
return [{ json: { ...$json, execution_plan: executionPlan, pack_orchestration: { started_at: new Date().toISOString(), expected_duration_seconds: 180 } } }];

// Capture cwf210_result after sub-workflow CWF-210
const subOutput = $json || {};
let parentCtx = {};
try { parentCtx = $('Execution Planner Node').first().json || {}; } catch(e) {}
const acc = { ...parentCtx };

acc["cwf210_result"] = {
  status: subOutput.status || 'SUCCESS',
  payload: subOutput.payload || subOutput,
  captured_at: new Date().toISOString()
};
return [{ json: acc }];

// Capture cwf220_result after sub-workflow CWF-220
const subOutput = $json || {};
let parentCtx = {};
try { parentCtx = $('Execution Planner Node').first().json || {}; } catch(e) {}
const acc = { ...parentCtx };
try { const c = $('Capture CWF-210 Result').first(); if (c) acc["cwf210_result"] = c.json["cwf210_result"] || c.json; } catch(e) {}
acc["cwf220_result"] = {
  status: subOutput.status || 'SUCCESS',
  payload: subOutput.payload || subOutput,
  captured_at: new Date().toISOString()
};
return [{ json: acc }];

// Capture cwf230_result after sub-workflow CWF-230
const subOutput = $json || {};
let parentCtx = {};
try { parentCtx = $('Execution Planner Node').first().json || {}; } catch(e) {}
const acc = { ...parentCtx };
try { const c = $('Capture CWF-210 Result').first(); if (c) acc["cwf210_result"] = c.json["cwf210_result"] || c.json; } catch(e) {}
  try { const c = $('Capture CWF-220 Result').first(); if (c) acc["cwf220_result"] = c.json["cwf220_result"] || c.json; } catch(e) {}
acc["cwf230_result"] = {
  status: subOutput.status || 'SUCCESS',
  payload: subOutput.payload || subOutput,
  captured_at: new Date().toISOString()
};
return [{ json: acc }];

// Capture cwf240_result after sub-workflow CWF-240
const subOutput = $json || {};
let parentCtx = {};
try { parentCtx = $('Execution Planner Node').first().json || {}; } catch(e) {}
const acc = { ...parentCtx };
try { const c = $('Capture CWF-210 Result').first(); if (c) acc["cwf210_result"] = c.json["cwf210_result"] || c.json; } catch(e) {}
  try { const c = $('Capture CWF-220 Result').first(); if (c) acc["cwf220_result"] = c.json["cwf220_result"] || c.json; } catch(e) {}
  try { const c = $('Capture CWF-230 Result').first(); if (c) acc["cwf230_result"] = c.json["cwf230_result"] || c.json; } catch(e) {}
acc["cwf240_result"] = {
  status: subOutput.status || 'SUCCESS',
  payload: subOutput.payload || subOutput,
  captured_at: new Date().toISOString()
};
return [{ json: acc }];

// Phase-2 chain validation: pass if all children returned SUCCESS/COMPLETED.
const childResults = {
  CWF_210: $json.cwf210_result,
  CWF_220: $json.cwf220_result,
  CWF_230: $json.cwf230_result,
  CWF_240: $json.cwf240_result
};
const allHealthy = Object.values(childResults).every(r => r && (r.status === 'SUCCESS' || r.status === 'COMPLETED'));
const validationOk = allHealthy;
return [{ json: { ...$json, pack_validation: { child_results_aggregated: childResults, all_children_healthy: allHealthy, validation_ok: validationOk, route_to_error: !validationOk, phase2_acceptance: 'chain_healthy_required' } } }];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    ...$json,
    dossier_write: {
      mutation_type: 'namespace_update',
      target: 'dossier.script',
      timestamp: new Date().toISOString(),
      writer_id: 'WF-200',
      pack_context: $json.pack_context,
      child_results: $json.pack_validation.child_results_aggregated,
      audit_entry: 'script-intelligence-pack-completion from WF-200'
    }
  }
}];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    ...$json,
    se_route_runs_write: {
      operation: 'record_pack_execution',
      pack_id: 'WF-200',
      dossier_id: $json.dossier_id,
      child_workflows_executed: ['CWF-210', 'CWF-220', 'CWF-230', 'CWF-240'],
      execution_status: 'COMPLETED',
      script_finalized: $json.pack_validation.script_finalized,
      quality_approved: $json.pack_validation.quality_approved,
      timestamp: new Date().toISOString()
    }
  }
}];

if ($json.pack_validation.route_to_error) return [];
const fs = require('fs');
const path = require('path');

const now = new Date().toISOString();
const completion_packet = {
  instance_id: 'WF-200-COMP-' + Date.now(),
  artifact_family: 'script_intelligence_result',
  schema_version: '1.0.0',
  producer_workflow: 'WF-200',
  dossier_ref: $json.dossier_id,
  created_at: now,
  status: 'CREATED',
  payload: {
    pack_executed: 'WF-200',
    script_finalized: $json.pack_validation.script_finalized,
        quality_approved: $json.pack_validation.quality_approved,
    next_workflow: 'WF-300',
    child_packets: ["CWF-210_output","CWF-220_output","CWF-230_output","CWF-240_output"]
  }
};

const repoRoot = 'C:/ShadowEmpire-Git';
const dataDir = path.join(repoRoot, 'data');
const packetIndexPath = path.join(dataDir, 'se_packet_index.json');
if (!fs.existsSync(dataDir)) fs.mkdirSync(dataDir, { recursive: true });

let index = { entries: [], total_entries: 0, last_updated: now };
if (fs.existsSync(packetIndexPath)) {
  const parsed = JSON.parse(fs.readFileSync(packetIndexPath, 'utf8'));
  index = {
    ...index,
    ...parsed,
    entries: Array.isArray(parsed.entries)
      ? parsed.entries
      : (Array.isArray(parsed.packets) ? parsed.packets : [])
  };
}

index.entries.push({
  packet_id: completion_packet.instance_id,
  instance_id: completion_packet.instance_id,
  artifact_family: completion_packet.artifact_family,
  schema_version: completion_packet.schema_version,
  producer_workflow: completion_packet.producer_workflow,
  dossier_ref: completion_packet.dossier_ref,
  created_at: completion_packet.created_at,
  status: completion_packet.status,
  payload: completion_packet.payload
});
index.total_entries = index.entries.length;
index.last_updated = now;

fs.writeFileSync(packetIndexPath, JSON.stringify(index, null, 2), 'utf8');

return [{
  json: {
    workflow_id: 'WF-200',
    execution_status: 'SUCCESS',
    completion_packet,
    packet_persistence: {
      packet_index_path: packetIndexPath,
      packet_entries: index.entries.length,
      persisted_at: now
    }
  }
}];

if (!$json.pack_validation.route_to_error) return [];
return [{
  json: {
    workflow_id: 'WF-200',
    routing_decision: 'ERROR',
    route_to_workflow: 'WF-900',
    error_message: 'Pack validation failed or child workflow failed',
    failure_context: $json.pack_validation,
    child_results: $json.pack_validation.child_results_aggregated
  }
}];
